 1→{
 2→  "name": "basement-lab",
 3→  "version": "1.0.0",
 4→  "description": "12-month bodybuilding transformation tracker PWA",
 5→  "scripts": {
 6→    "start": "npx serve",
 7→    "validate": "node tests/validate.js",
 8→    "test": "npx playwright test",
 9→    "test:headed": "npx playwright test --headed"
10→  },
11→  "devDependencies": {
12→    "@playwright/test": "1.57.0",
13→    "serve": "^14.2.0"
14→  }
15→}
16→

   1→/* Basement Lab - Multi-Theme System */
   2→
   3→/* =============================================
   4→   BASE VARIABLES (shared across all themes)
   5→   ============================================= */
   6→:root {
   7→  --radius: 8px;
   8→  --transition: 0.2s;
   9→  --danger: #ff4444;
  10→  --warning: #ff9800;
  11→}
  12→
  13→/* =============================================
  14→   THEME-SPECIFIC VARIABLES
  15→   (accent colors, fonts, effects)
  16→   ============================================= */
  17→
  18→/* Cyberpunk (default) - Neon glow, high contrast, monospace */
  19→[data-theme="cyberpunk"] {
  20→  --accent: #00ff88;
  21→  --accent-dim: #00cc6a;
  22→  --font-family: 'Courier New', monospace;
  23→  --glow: 0 0 20px rgba(0, 255, 136, 0.3);
  24→  --shadow: none;
  25→}
  26→
  27→/* Material - Soft shadows, calm, system font */
  28→[data-theme="material"] {
  29→  --accent: #009688;
  30→  --accent-dim: #00796b;
  31→  --font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  32→  --glow: none;
  33→  --shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  34→}
  35→
  36→/* Ocean - Cool, clean, system font */
  37→[data-theme="ocean"] {
  38→  --accent: #2196f3;
  39→  --accent-dim: #1976d2;
  40→  --font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  41→  --glow: none;
  42→  --shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
  43→}
  44→
  45→/* Ember - Warm, energetic, monospace */
  46→[data-theme="ember"] {
  47→  --accent: #ff7043;
  48→  --accent-dim: #f4511e;
  49→  --font-family: 'Courier New', monospace;
  50→  --glow: 0 0 20px rgba(255, 112, 67, 0.3);
  51→  --shadow: none;
  52→}
  53→
  54→/* =============================================
  55→   MODE-SPECIFIC VARIABLES
  56→   (backgrounds, text colors)
  57→   ============================================= */
  58→
  59→/* Dark mode */
  60→[data-mode="dark"] {
  61→  --bg-primary: #0a0a0a;
  62→  --bg-secondary: #111111;
  63→  --bg-card: #1a1a1a;
  64→  --text-primary: #e0e0e0;
  65→  --text-secondary: #aaaaaa;
  66→  --border: #333333;
  67→}
  68→
  69→/* Light mode */
  70→[data-mode="light"] {
  71→  --bg-primary: #f5f5f5;
  72→  --bg-secondary: #ffffff;
  73→  --bg-card: #ffffff;
  74→  --text-primary: #1a1a1a;
  75→  --text-secondary: #666666;
  76→  --border: #dddddd;
  77→}
  78→
  79→/* =============================================
  80→   THEME + MODE COMBINATION OVERRIDES
  81→   (accent adjustments for light backgrounds)
  82→   ============================================= */
  83→
  84→/* Cyberpunk light - darker green for readability */
  85→[data-theme="cyberpunk"][data-mode="light"] {
  86→  --accent: #00994d;
  87→  --accent-dim: #007a3d;
  88→  --glow: 0 0 20px rgba(0, 153, 77, 0.2);
  89→}
  90→
  91→/* Material light - slightly darker teal */
  92→[data-theme="material"][data-mode="light"] {
  93→  --accent: #00796b;
  94→  --accent-dim: #00695c;
  95→  --shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  96→}
  97→
  98→/* Ocean light - slightly darker blue */
  99→[data-theme="ocean"][data-mode="light"] {
 100→  --accent: #1976d2;
 101→  --accent-dim: #1565c0;
 102→  --shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
 103→}
 104→
 105→/* Ember light - slightly darker orange */
 106→[data-theme="ember"][data-mode="light"] {
 107→  --accent: #f4511e;
 108→  --accent-dim: #e64a19;
 109→  --glow: 0 0 20px rgba(244, 81, 30, 0.15);
 110→}
 111→
 112→/* =============================================
 113→   GLOBAL RESET
 114→   ============================================= */
 115→* {
 116→  margin: 0;
 117→  padding: 0;
 118→  box-sizing: border-box;
 119→}
 120→
 121→body {
 122→  font-family: var(--font-family);
 123→  background: var(--bg-primary);
 124→  color: var(--text-primary);
 125→  min-height: 100vh;
 126→  display: flex;
 127→  flex-direction: column;
 128→  -webkit-font-smoothing: antialiased;
 129→}
 130→
 131→/* =============================================
 132→   HEADER
 133→   ============================================= */
 134→header {
 135→  background: var(--bg-secondary);
 136→  padding: 1rem;
 137→  text-align: center;
 138→  border-bottom: 1px solid var(--accent);
 139→  position: sticky;
 140→  top: 0;
 141→  z-index: 100;
 142→  position: relative;
 143→  box-shadow: var(--shadow);
 144→}
 145→
 146→.settings-btn {
 147→  position: absolute;
 148→  top: 50%;
 149→  right: 1rem;
 150→  transform: translateY(-50%);
 151→  background: transparent;
 152→  border: 1px solid var(--border);
 153→  color: var(--text-secondary);
 154→  width: 36px;
 155→  height: 36px;
 156→  border-radius: 50%;
 157→  cursor: pointer;
 158→  display: flex;
 159→  align-items: center;
 160→  justify-content: center;
 161→  font-size: 1.2rem;
 162→  transition: all var(--transition);
 163→}
 164→
 165→.settings-btn:hover {
 166→  border-color: var(--accent);
 167→  color: var(--accent);
 168→}
 169→
 170→header h1 {
 171→  font-size: 1.5rem;
 172→  letter-spacing: 0.3em;
 173→  color: var(--accent);
 174→  text-shadow: var(--glow);
 175→}
 176→
 177→#day-counter {
 178→  font-size: 1rem;
 179→  color: var(--text-secondary);
 180→  margin-top: 0.5rem;
 181→}
 182→
 183→#day-counter span {
 184→  color: var(--accent);
 185→  font-weight: bold;
 186→}
 187→
 188→/* =============================================
 189→   SESSION PROGRESS BAR
 190→   ============================================= */
 191→#session-progress {
 192→  position: absolute;
 193→  bottom: 0;
 194→  left: 0;
 195→  right: 0;
 196→  height: 3px;
 197→  background: transparent;
 198→}
 199→
 200→#session-progress-bar {
 201→  height: 100%;
 202→  width: 0%;
 203→  background: var(--accent);
 204→  box-shadow: var(--glow);
 205→  transition: width 0.4s ease;
 206→}
 207→
 208→/* =============================================
 209→   MAIN CONTENT
 210→   ============================================= */
 211→main {
 212→  flex: 1;
 213→  padding: 1rem;
 214→  overflow-y: auto;
 215→  padding-bottom: 100px;
 216→}
 217→
 218→.card {
 219→  background: var(--bg-card);
 220→  border: 1px solid var(--border);
 221→  border-radius: var(--radius);
 222→  padding: 1rem;
 223→  margin-bottom: 1rem;
 224→  box-shadow: var(--shadow);
 225→}
 226→
 227→#workout-header {
 228→  border-bottom: 1px solid var(--border);
 229→  padding-bottom: 1rem;
 230→  margin-bottom: 1rem;
 231→}
 232→
 233→#workout-name {
 234→  font-size: 1.3rem;
 235→  color: var(--accent);
 236→  margin-bottom: 0.25rem;
 237→}
 238→
 239→#workout-focus {
 240→  font-size: 1rem;
 241→  color: var(--text-secondary);
 242→}
 243→
 244→/* =============================================
 245→   EXERCISE ITEMS
 246→   ============================================= */
 247→.exercise {
 248→  background: var(--bg-secondary);
 249→  border: 1px solid var(--border);
 250→  border-radius: 6px;
 251→  padding: 1rem;
 252→  margin-bottom: 0.75rem;
 253→  box-shadow: var(--shadow);
 254→}
 255→
 256→.exercise-header {
 257→  display: flex;
 258→  justify-content: space-between;
 259→  align-items: flex-start;
 260→  margin-bottom: 0.5rem;
 261→}
 262→
 263→.exercise-name {
 264→  font-size: 1.1rem;
 265→  font-weight: bold;
 266→  color: var(--text-primary);
 267→  flex: 1;
 268→}
 269→
 270→.video-btn {
 271→  background: transparent;
 272→  border: 1px solid var(--accent);
 273→  color: var(--accent);
 274→  padding: 0.25rem 0.5rem;
 275→  font-size: 0.9rem;
 276→  border-radius: 4px;
 277→  cursor: pointer;
 278→  font-family: inherit;
 279→  transition: all var(--transition);
 280→}
 281→
 282→.video-btn:hover {
 283→  background: var(--accent);
 284→  color: var(--bg-primary);
 285→}
 286→
 287→.video-btn:disabled {
 288→  opacity: 0.3;
 289→  cursor: not-allowed;
 290→}
 291→
 292→.exercise-details {
 293→  display: flex;
 294→  gap: 1rem;
 295→  font-size: 1rem;
 296→  color: var(--text-secondary);
 297→  margin-bottom: 0.5rem;
 298→}
 299→
 300→.exercise-details span {
 301→  display: flex;
 302→  align-items: center;
 303→  gap: 0.25rem;
 304→}
 305→
 306→.exercise-note {
 307→  font-size: 0.95rem;
 308→  color: var(--accent-dim);
 309→  font-style: italic;
 310→  padding-top: 0.5rem;
 311→  border-top: 1px dashed var(--border);
 312→}
 313→
 314→/* =============================================
 315→   COMPLETED EXERCISE STATE
 316→   ============================================= */
 317→.exercise.completed {
 318→  border-left: 3px solid var(--accent);
 319→  opacity: 0.85;
 320→}
 321→
 322→.exercise.completed .exercise-name {
 323→  color: var(--accent);
 324→}
 325→
 326→/* Done Button */
 327→.done-btn {
 328→  background: transparent;
 329→  border: 1px solid var(--accent);
 330→  color: var(--accent);
 331→  padding: 0.4rem 0.75rem;
 332→  font-size: 0.85rem;
 333→  font-family: inherit;
 334→  border-radius: 4px;
 335→  cursor: pointer;
 336→  transition: all var(--transition);
 337→  text-transform: uppercase;
 338→  letter-spacing: 0.05em;
 339→  font-weight: bold;
 340→}
 341→
 342→.done-btn:hover {
 343→  background: var(--accent);
 344→  color: var(--bg-primary);
 345→}
 346→
 347→.done-btn.is-done {
 348→  background: var(--accent);
 349→  color: var(--bg-primary);
 350→}
 351→
 352→/* =============================================
 353→   WEIGHT INPUT
 354→   ============================================= */
 355→.weight-input {
 356→  display: flex;
 357→  align-items: center;
 358→  gap: 0.5rem;
 359→  margin-top: 0.75rem;
 360→  padding-top: 0.75rem;
 361→  border-top: 1px solid var(--border);
 362→}
 363→
 364→.weight-input label {
 365→  font-size: 0.95rem;
 366→  color: var(--text-secondary);
 367→}
 368→
 369→.weight-input input {
 370→  background: var(--bg-primary);
 371→  border: 1px solid var(--border);
 372→  color: var(--text-primary);
 373→  padding: 0.5rem;
 374→  width: 80px;
 375→  font-family: inherit;
 376→  font-size: 1.1rem;
 377→  border-radius: 4px;
 378→  text-align: center;
 379→}
 380→
 381→.weight-input input:focus {
 382→  outline: none;
 383→  border-color: var(--accent);
 384→  box-shadow: var(--glow);
 385→}
 386→
 387→.weight-input .unit {
 388→  font-size: 0.95rem;
 389→  color: var(--text-secondary);
 390→}
 391→
 392→/* Weight Controls (+/- buttons) */
 393→.weight-controls {
 394→  display: flex;
 395→  align-items: center;
 396→  gap: 0.5rem;
 397→}
 398→
 399→.weight-btn {
 400→  width: 32px;
 401→  height: 32px;
 402→  border-radius: 50%;
 403→  border: 1px solid var(--accent);
 404→  background: transparent;
 405→  color: var(--accent);
 406→  font-size: 1.2rem;
 407→  font-family: inherit;
 408→  cursor: pointer;
 409→  display: flex;
 410→  align-items: center;
 411→  justify-content: center;
 412→  transition: all var(--transition);
 413→}
 414→
 415→.weight-btn:hover {
 416→  background: var(--accent);
 417→  color: var(--bg-primary);
 418→}
 419→
 420→.weight-btn:active {
 421→  transform: scale(0.95);
 422→}
 423→
 424→.suggested-hint {
 425→  font-size: 0.9rem;
 426→  color: var(--text-secondary);
 427→  font-style: italic;
 428→  margin-left: 0.5rem;
 429→}
 430→
 431→/* =============================================
 432→   FEEDBACK SECTION
 433→   ============================================= */
 434→.feedback-section {
 435→  margin-top: 0.75rem;
 436→  padding-top: 0.75rem;
 437→  border-top: 1px solid var(--border);
 438→}
 439→
 440→.feedback-toggle {
 441→  background: transparent;
 442→  border: 1px solid var(--border);
 443→  color: var(--text-secondary);
 444→  padding: 0.4rem 0.75rem;
 445→  font-size: 0.85rem;
 446→  font-family: inherit;
 447→  border-radius: 4px;
 448→  cursor: pointer;
 449→  transition: all var(--transition);
 450→}
 451→
 452→.feedback-toggle:hover {
 453→  border-color: var(--accent);
 454→  color: var(--accent);
 455→}
 456→
 457→.feedback-content {
 458→  display: none;
 459→  margin-top: 0.75rem;
 460→}
 461→
 462→.feedback-section.expanded .feedback-content {
 463→  display: block;
 464→}
 465→
 466→.feedback-section.expanded .feedback-toggle {
 467→  border-color: var(--accent);
 468→  color: var(--accent);
 469→}
 470→
 471→/* Difficulty Input */
 472→.difficulty-input {
 473→  margin-bottom: 0.75rem;
 474→}
 475→
 476→.difficulty-input label {
 477→  font-size: 0.95rem;
 478→  color: var(--text-secondary);
 479→  display: block;
 480→  margin-bottom: 0.5rem;
 481→}
 482→
 483→.difficulty-buttons {
 484→  display: flex;
 485→  gap: 0.5rem;
 486→}
 487→
 488→.difficulty-btn {
 489→  flex: 1;
 490→  background: transparent;
 491→  border: 1px solid var(--border);
 492→  color: var(--text-secondary);
 493→  padding: 0.5rem 0.25rem;
 494→  font-size: 0.85rem;
 495→  font-family: inherit;
 496→  border-radius: 4px;
 497→  cursor: pointer;
 498→  transition: all var(--transition);
 499→  text-transform: uppercase;
 500→  letter-spacing: 0.05em;
 501→}
 502→
 503→.difficulty-btn:hover {
 504→  border-color: var(--text-primary);
 505→  color: var(--text-primary);
 506→}
 507→
 508→.difficulty-btn[data-difficulty="failed"] {
 509→  border-color: var(--danger);
 510→  color: var(--danger);
 511→  opacity: 0.7;
 512→}
 513→
 514→.difficulty-btn[data-difficulty="failed"]:hover,
 515→.difficulty-btn[data-difficulty="failed"].selected {
 516→  background: var(--danger);
 517→  color: var(--bg-primary);
 518→  opacity: 1;
 519→}
 520→
 521→.difficulty-btn[data-difficulty="easy"] {
 522→  border-color: var(--text-secondary);
 523→  color: var(--text-secondary);
 524→}
 525→
 526→.difficulty-btn[data-difficulty="easy"]:hover,
 527→.difficulty-btn[data-difficulty="easy"].selected {
 528→  background: var(--text-secondary);
 529→  color: var(--bg-primary);
 530→}
 531→
 532→.difficulty-btn[data-difficulty="good"] {
 533→  border-color: var(--accent);
 534→  color: var(--accent);
 535→}
 536→
 537→.difficulty-btn[data-difficulty="good"]:hover,
 538→.difficulty-btn[data-difficulty="good"].selected {
 539→  background: var(--accent);
 540→  color: var(--bg-primary);
 541→}
 542→
 543→.difficulty-btn[data-difficulty="hard"] {
 544→  border-color: var(--warning);
 545→  color: var(--warning);
 546→}
 547→
 548→.difficulty-btn[data-difficulty="hard"]:hover,
 549→.difficulty-btn[data-difficulty="hard"].selected {
 550→  background: var(--warning);
 551→  color: var(--bg-primary);
 552→}
 553→
 554→/* Failed Details */
 555→.failed-details {
 556→  display: none;
 557→  margin-top: 0.75rem;
 558→  padding: 0.75rem;
 559→  background: rgba(255, 68, 68, 0.1);
 560→  border: 1px solid var(--danger);
 561→  border-radius: 4px;
 562→}
 563→
 564→.failed-details.visible {
 565→  display: block;
 566→}
 567→
 568→.slider-group {
 569→  margin-bottom: 0.5rem;
 570→}
 571→
 572→.slider-group:last-child {
 573→  margin-bottom: 0;
 574→}
 575→
 576→.slider-group label {
 577→  display: block;
 578→  font-size: 0.9rem;
 579→  color: var(--text-secondary);
 580→  margin-bottom: 0.25rem;
 581→}
 582→
 583→.slider-value {
 584→  color: var(--danger);
 585→  font-weight: bold;
 586→}
 587→
 588→.failed-set-slider,
 589→.failed-rep-slider {
 590→  width: 100%;
 591→  height: 6px;
 592→  -webkit-appearance: none;
 593→  appearance: none;
 594→  background: var(--border);
 595→  border-radius: 3px;
 596→  outline: none;
 597→}
 598→
 599→.failed-set-slider::-webkit-slider-thumb,
 600→.failed-rep-slider::-webkit-slider-thumb {
 601→  -webkit-appearance: none;
 602→  appearance: none;
 603→  width: 18px;
 604→  height: 18px;
 605→  background: var(--danger);
 606→  border-radius: 50%;
 607→  cursor: pointer;
 608→}
 609→
 610→.failed-set-slider::-moz-range-thumb,
 611→.failed-rep-slider::-moz-range-thumb {
 612→  width: 18px;
 613→  height: 18px;
 614→  background: var(--danger);
 615→  border-radius: 50%;
 616→  cursor: pointer;
 617→  border: none;
 618→}
 619→
 620→/* Notes Input */
 621→.notes-input {
 622→  margin-top: 0.75rem;
 623→}
 624→
 625→.notes-field {
 626→  width: 100%;
 627→  background: var(--bg-primary);
 628→  border: 1px solid var(--border);
 629→  color: var(--text-primary);
 630→  padding: 0.5rem;
 631→  font-family: inherit;
 632→  font-size: 0.95rem;
 633→  border-radius: 4px;
 634→  resize: vertical;
 635→  min-height: 2.5rem;
 636→  max-height: 6rem;
 637→}
 638→
 639→.notes-field:focus {
 640→  outline: none;
 641→  border-color: var(--accent);
 642→  box-shadow: var(--glow);
 643→}
 644→
 645→.notes-field::placeholder {
 646→  color: var(--text-secondary);
 647→  opacity: 0.6;
 648→}
 649→
 650→/* =============================================
 651→   EXERCISE TIMER
 652→   ============================================= */
 653→.timer-section {
 654→  display: flex;
 655→  flex-wrap: wrap;
 656→  gap: 0.5rem;
 657→  margin-top: 0.75rem;
 658→  padding-top: 0.75rem;
 659→  border-top: 1px solid var(--border);
 660→}
 661→
 662→.timer-widget {
 663→  display: flex;
 664→  align-items: center;
 665→  gap: 0.5rem;
 666→  background: var(--bg-primary);
 667→  border: 1px solid var(--border);
 668→  border-radius: 4px;
 669→  padding: 0.4rem 0.6rem;
 670→  flex: 1;
 671→  min-width: 0;
 672→}
 673→
 674→.timer-label {
 675→  font-size: 0.7rem;
 676→  color: var(--text-secondary);
 677→  text-transform: uppercase;
 678→  letter-spacing: 0.05em;
 679→  flex-shrink: 0;
 680→}
 681→
 682→.timer-display {
 683→  font-size: 1.1rem;
 684→  font-weight: bold;
 685→  color: var(--accent);
 686→  font-variant-numeric: tabular-nums;
 687→  min-width: 2.5em;
 688→  text-align: center;
 689→}
 690→
 691→.timer-display.timer-done {
 692→  color: var(--accent);
 693→  text-shadow: var(--glow);
 694→}
 695→
 696→.timer-start-pause,
 697→.timer-reset {
 698→  background: transparent;
 699→  border: 1px solid var(--accent);
 700→  color: var(--accent);
 701→  padding: 0.2rem 0.5rem;
 702→  font-size: 0.75rem;
 703→  font-family: inherit;
 704→  border-radius: 3px;
 705→  cursor: pointer;
 706→  transition: all var(--transition);
 707→  text-transform: uppercase;
 708→  letter-spacing: 0.05em;
 709→  flex-shrink: 0;
 710→}
 711→
 712→.timer-start-pause:hover,
 713→.timer-reset:hover {
 714→  background: var(--accent);
 715→  color: var(--bg-primary);
 716→}
 717→
 718→.timer-start-pause:disabled {
 719→  opacity: 0.5;
 720→  cursor: default;
 721→}
 722→
 723→.timer-start-pause:disabled:hover {
 724→  background: transparent;
 725→  color: var(--accent);
 726→}
 727→
 728→.timer-reset {
 729→  border-color: var(--border);
 730→  color: var(--text-secondary);
 731→}
 732→
 733→.timer-reset:hover {
 734→  border-color: var(--text-secondary);
 735→  background: var(--text-secondary);
 736→  color: var(--bg-primary);
 737→}
 738→
 739→/* =============================================
 740→   REST DAY
 741→   ============================================= */
 742→#rest-day {
 743→  text-align: center;
 744→  padding: 3rem 1rem;
 745→}
 746→
