  1→/**
  2→ * Basement Lab - Exercise Timer Module
  3→ * Provides countdown timers for timed exercises and rest periods.
  4→ * Uses Web Audio API for completion beep.
  5→ */
  6→
  7→const ExerciseTimer = (() => {
  8→  // Track active timers by element id
  9→  const timers = {};
 10→
 11→  // Shared AudioContext (created on first user interaction)
 12→  let audioCtx = null;
 13→
 14→  /**
 15→   * Escape a string for safe insertion into HTML.
 16→   */
 17→  function escapeHTML(str) {
 18→    return String(str)
 19→      .replace(/&/g, '&amp;')
 20→      .replace(/</g, '&lt;')
 21→      .replace(/>/g, '&gt;')
 22→      .replace(/"/g, '&quot;')
 23→      .replace(/'/g, '&#39;');
 24→  }
 25→
 26→  function getAudioContext() {
 27→    if (!audioCtx) {
 28→      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
 29→    }
 30→    return audioCtx;
 31→  }
 32→
 33→  /**
 34→   * Create and play a single oscillator tone.
 35→   */
 36→  function createTone(ctx, freq, startTime, duration) {
 37→    const osc = ctx.createOscillator();
 38→    const gain = ctx.createGain();
 39→    osc.type = 'square';
 40→    osc.frequency.value = freq;
 41→    gain.gain.setValueAtTime(0.15, startTime);
 42→    gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);
 43→    osc.connect(gain);
 44→    gain.connect(ctx.destination);
 45→    osc.start(startTime);
 46→    osc.stop(startTime + duration);
 47→  }
 48→
 49→  /**
 50→   * Play a short beep using Web Audio API.
 51→   * Two-tone descending beep for a "done" feel.
 52→   */
 53→  function playBeep() {
 54→    try {
 55→      const ctx = getAudioContext();
 56→      const now = ctx.currentTime;
 57→      createTone(ctx, 880, now, 0.15);
 58→      createTone(ctx, 660, now + 0.15, 0.2);
 59→    } catch (e) {
 60→      // Audio not available — fail silently
 61→    }
 62→  }
 63→
 64→  /**
 65→   * Parse a time string like '45s', '60s', '90s' into seconds.
 66→   * Returns null if not a valid timer-compatible string.
 67→   * Excludes patterns like '45 mins', '20 mins', 'N/A', '0s'.
 68→   */
 69→  function parseSeconds(str) {
 70→    if (!str || str === 'N/A') return null;
 71→    const match = String(str).match(/^(\d+)s$/);
 72→    if (match) {
 73→      const val = parseInt(match[1], 10);
 74→      return val > 0 ? val : null;
 75→    }
 76→    return null;
 77→  }
 78→
 79→  /**
 80→   * Format seconds as M:SS or just SS.
 81→   */
 82→  function formatTime(seconds) {
 83→    const m = Math.floor(seconds / 60);
 84→    const s = seconds % 60;
 85→    if (m > 0) {
 86→      return `${m}:${String(s).padStart(2, '0')}`;
 87→    }
 88→    return String(s);
 89→  }
 90→
 91→  /**
 92→   * Create a timer instance for a given container element.
 93→   * @param {string} id - Unique identifier for this timer
 94→   * @param {number} duration - Duration in seconds
 95→   * @param {HTMLElement} container - The .timer-widget element
 96→   */
 97→  function createTimer(id, duration, container) {
 98→    // Clean up any existing timer with this id
 99→    if (timers[id]) {
100→      clearInterval(timers[id].interval);
101→    }
102→
103→    const state = {
104→      duration: duration,
105→      remaining: duration,
106→      running: false,
107→      finished: false,
108→      interval: null,
109→    };
110→
111→    timers[id] = state;
112→
113→    const display = container.querySelector('.timer-display');
114→    const startPauseBtn = container.querySelector('.timer-start-pause');
115→    const resetBtn = container.querySelector('.timer-reset');
116→
117→    function updateUI() {
118→      display.textContent = formatTime(state.remaining);
119→
120→      if (state.finished) {
121→        display.classList.add('timer-done');
122→        startPauseBtn.textContent = 'DONE';
123→        startPauseBtn.disabled = true;
124→      } else {
125→        display.classList.remove('timer-done');
126→        startPauseBtn.disabled = false;
127→        startPauseBtn.textContent = state.running ? 'PAUSE' : 'START';
128→      }
129→    }
130→
131→    function tick() {
132→      if (state.remaining <= 0) {
133→        clearInterval(state.interval);
134→        state.interval = null;
135→        state.running = false;
136→        state.finished = true;
137→        playBeep();
138→        updateUI();
139→        return;
140→      }
141→      state.remaining--;
142→      updateUI();
143→    }
144→
145→    function startPause() {
146→      if (state.finished) return;
147→
148→      if (state.running) {
149→        // Pause
150→        clearInterval(state.interval);
151→        state.interval = null;
152→        state.running = false;
153→      } else {
154→        // Start
155→        state.running = true;
156→        state.interval = setInterval(tick, 1000);
157→      }
158→      updateUI();
159→    }
160→
161→    function reset() {
162→      clearInterval(state.interval);
163→      state.interval = null;
164→      state.running = false;
165→      state.finished = false;
166→      state.remaining = state.duration;
167→      updateUI();
168→    }
169→
170→    startPauseBtn.addEventListener('click', startPause);
171→    resetBtn.addEventListener('click', reset);
172→
173→    updateUI();
174→  }
175→
176→  /**
177→   * Generate the HTML for a timer widget.
178→   * @param {string} id - Unique id for this timer
179→   * @param {number} seconds - Duration in seconds
180→   * @param {string} label - Label like "EXERCISE" or "REST"
181→   * @returns {string} HTML string
182→   */
183→  function renderTimerHTML(id, seconds, label) {
184→    return `
185→      <div class="timer-widget" data-timer-id="${escapeHTML(id)}" data-timer-duration="${seconds}">
186→        <span class="timer-label">${escapeHTML(label)}</span>
187→        <span class="timer-display">${formatTime(seconds)}</span>
188→        <button class="timer-start-pause" type="button">START</button>
189→        <button class="timer-reset" type="button">RST</button>
190→      </div>
191→    `;
192→  }
193→
194→  /**
195→   * Initialize all timer widgets currently in the DOM.
196→   * Call this after rendering exercise cards.
197→   */
198→  function initAll() {
199→    destroyAll();
200→
201→    document.querySelectorAll('.timer-widget').forEach(widget => {
202→      const id = widget.dataset.timerId;
203→      const duration = parseInt(widget.dataset.timerDuration, 10);
204→      if (id && duration > 0) {
205→        createTimer(id, duration, widget);
206→      }
207→    });
208→  }
209→
210→  /**
211→   * Destroy all active timers (e.g., on day change).
212→   */
213→  function destroyAll() {
214→    for (const id in timers) {
215→      clearInterval(timers[id].interval);
216→      delete timers[id];
217→    }
218→  }
219→
220→  return {
221→    parseSeconds,
222→    formatTime,
223→    renderTimerHTML,
224→    initAll,
225→    destroyAll,
226→    playBeep,
227→  };
228→})();
