  1→/**
  2→ * Basement Lab - Workout Tracker
  3→ * State management and UI logic
  4→ */
  5→
  6→const STATE_KEY = 'basement_lab_state';
  7→const LOG_KEY = 'basement_lab_log';
  8→const THEME_KEY = 'basement_lab_theme';
  9→const MODE_KEY = 'basement_lab_mode';
 10→
 11→let programData = null;
 12→let currentState = null;
 13→
 14→// Initialize app
 15→async function init() {
 16→  loadState();
 17→  initTheme();
 18→  await loadProgram();
 19→  render();
 20→  bindEvents();
 21→}
 22→
 23→// Initialize theme and mode from localStorage or system preference
 24→function initTheme() {
 25→  const savedTheme = localStorage.getItem(THEME_KEY) || 'cyberpunk';
 26→  const savedMode = localStorage.getItem(MODE_KEY) ||
 27→    (window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark');
 28→
 29→  setTheme(savedTheme);
 30→  setMode(savedMode);
 31→  updateSettingsUI();
 32→}
 33→
 34→// Set theme (cyberpunk, material, ocean, ember)
 35→function setTheme(theme) {
 36→  document.documentElement.setAttribute('data-theme', theme);
 37→  localStorage.setItem(THEME_KEY, theme);
 38→  updateSettingsUI();
 39→}
 40→
 41→// Set mode (dark, light)
 42→function setMode(mode) {
 43→  document.documentElement.setAttribute('data-mode', mode);
 44→  localStorage.setItem(MODE_KEY, mode);
 45→
 46→  // Update meta theme-color based on mode
 47→  const metaThemeColor = document.querySelector('meta[name="theme-color"]');
 48→  if (metaThemeColor) {
 49→    metaThemeColor.setAttribute('content', mode === 'light' ? '#f5f5f5' : '#0a0a0a');
 50→  }
 51→
 52→  updateSettingsUI();
 53→}
 54→
 55→// Update settings modal UI to reflect current theme/mode
 56→function updateSettingsUI() {
 57→  const currentTheme = document.documentElement.getAttribute('data-theme') || 'cyberpunk';
 58→  const currentMode = document.documentElement.getAttribute('data-mode') || 'dark';
 59→
 60→  // Update theme options
 61→  document.querySelectorAll('.theme-option').forEach(option => {
 62→    if (option.dataset.theme === currentTheme) {
 63→      option.classList.add('active');
 64→    } else {
 65→      option.classList.remove('active');
 66→    }
 67→  });
 68→
 69→  // Update mode buttons
 70→  document.querySelectorAll('.mode-btn').forEach(btn => {
 71→    if (btn.dataset.mode === currentMode) {
 72→      btn.classList.add('active');
 73→    } else {
 74→      btn.classList.remove('active');
 75→    }
 76→  });
 77→}
 78→
 79→// Open settings modal
 80→function openSettings() {
 81→  updateSettingsUI();
 82→  document.getElementById('settings-modal').classList.remove('hidden');
 83→}
 84→
 85→// Close settings modal
 86→function closeSettings() {
 87→  document.getElementById('settings-modal').classList.add('hidden');
 88→}
 89→
 90→// Load state from localStorage
 91→function loadState() {
 92→  const saved = localStorage.getItem(STATE_KEY);
 93→  if (saved) {
 94→    currentState = JSON.parse(saved);
 95→    // Validate globalDay: must be a positive integer
 96→    const day = Number(currentState.globalDay);
 97→    if (!Number.isInteger(day) || day < 1) {
 98→      currentState.globalDay = 1;
 99→    } else {
100→      currentState.globalDay = day;
101→    }
102→  } else {
103→    currentState = {
104→      globalDay: 1,
105→      currentPhase: 'p1'
106→    };
107→    saveState();
108→  }
109→}
110→
111→// Save state to localStorage
112→function saveState() {
113→  localStorage.setItem(STATE_KEY, JSON.stringify(currentState));
114→}
115→
116→// Load exercise log from localStorage
117→function loadLog() {
118→  const saved = localStorage.getItem(LOG_KEY);
119→  return saved ? JSON.parse(saved) : {};
120→}
121→
122→// Save exercise log to localStorage
123→function saveLog(log) {
124→  localStorage.setItem(LOG_KEY, JSON.stringify(log));
125→}
126→
127→// Load program data from JSON
128→async function loadProgram() {
129→  try {
130→    const response = await fetch('data/program.json');
131→    programData = await response.json();
132→  } catch (error) {
133→    console.error('Failed to load program:', error);
134→    document.getElementById('workout-name').textContent = 'Error loading program';
135→  }
136→}
137→
138→// Get current phase data
139→function getCurrentPhase() {
140→  if (!programData) return null;
141→  return programData.phases.find(p => p.id === currentState.currentPhase);
142→}
143→
144→// Get workout type for current day
145→function getWorkoutType() {
146→  const phase = getCurrentPhase();
147→  if (!phase || !phase.schedule_pattern) return null;
148→
149→  // Day 1 = index 0, so subtract 1
150→  const dayIndex = (currentState.globalDay - 1) % phase.schedule_pattern.length;
151→  return phase.schedule_pattern[dayIndex];
152→}
153→
154→// Get workout data for current day
155→function getTodaysWorkout() {
156→  const phase = getCurrentPhase();
157→  const workoutType = getWorkoutType();
158→
159→  if (!phase || !workoutType || workoutType === 'Rest') {
160→    return null;
161→  }
162→
163→  return phase.workouts[workoutType];
164→}
165→
166→// Render the UI
167→function render() {
168→  // Update day counter
169→  document.getElementById('current-day').textContent = currentState.globalDay;
170→
171→  const workout = getTodaysWorkout();
172→  const workoutCard = document.getElementById('workout-card');
173→  const restDay = document.getElementById('rest-day');
174→
175→  if (!workout) {
176→    // Rest day
177→    workoutCard.classList.add('hidden');
178→    restDay.classList.remove('hidden');
179→    document.getElementById('session-progress').style.display = 'none';
180→    return;
181→  }
182→
183→  document.getElementById('session-progress').style.display = '';
184→
185→  // Workout day
186→  workoutCard.classList.remove('hidden');
187→  restDay.classList.add('hidden');
188→
189→  document.getElementById('workout-name').textContent = workout.name;
190→  document.getElementById('workout-focus').textContent = workout.focus;
191→
192→  const exercisesList = document.getElementById('exercises-list');
193→  const log = loadLog();
194→
195→  exercisesList.innerHTML = workout.exercises.map((ex, index) => {
196→    const exerciseKey = `${currentState.globalDay}_${index}`;
197→    const logEntry = log[exerciseKey] || {};
198→    const currentWeight = logEntry.weight || '';
199→    const currentDifficulty = logEntry.difficulty || '';
200→    const currentNotes = logEntry.notes || '';

200→    const currentNotes = logEntry.notes || '';
201→
202→    // Calculate suggested weight for weight-based exercises
203→    const suggestedWeight = ex.uses_weight
204→      ? getSuggestedWeight(ex.name, ex.starting_weight, ex.weight_increment || 5)
205→      : null;
206→    const increment = ex.weight_increment || 5;
207→
208→    // Build weight input section
209→    let weightSection = '';
210→    if (ex.uses_weight) {
211→      weightSection = `
212→        <div class="weight-input">
213→          <label>Weight:</label>
214→          <div class="weight-controls">
215→            <button class="weight-btn" data-action="decrement" data-key="${exerciseKey}" data-increment="${increment}">-</button>
216→            <input type="number"
217→                   class="weight-field"
218→                   data-exercise="${ex.name}"
219→                   data-key="${exerciseKey}"
220→                   value="${currentWeight}"
221→                   placeholder="${suggestedWeight}">
222→            <button class="weight-btn" data-action="increment" data-key="${exerciseKey}" data-increment="${increment}">+</button>
223→          </div>
224→          <span class="unit">lbs</span>
