327→// Update session progress bar
328→function updateProgressBar() {
329→  const workout = getTodaysWorkout();
330→  const bar = document.getElementById('session-progress-bar');
331→  if (!workout || !bar) {
332→    if (bar) bar.style.width = '0%';
333→    return;
334→  }
335→
336→  const log = loadLog();
337→  const total = workout.exercises.length;
338→  let completed = 0;
339→
340→  workout.exercises.forEach((ex, index) => {
341→    const key = `${currentState.globalDay}_${index}`;
342→    if (log[key] && log[key].completed) {
343→      completed++;
344→    }
345→  });
346→
347→  const percent = total > 0 ? (completed / total) * 100 : 0;
348→  bar.style.width = `${percent}%`;
349→}
