373→// Get suggested weight with weekly progression logic
374→function getSuggestedWeight(exerciseName, startingWeight, increment = 5) {
375→  const log = loadLog();
376→  const currentWeek = Math.floor((currentState.globalDay - 1) / 7) + 1;
377→
378→  // Find last logged weight for this exercise
379→  let lastEntry = null;
380→  for (const key in log) {
381→    if (log[key].exercise === exerciseName) {
382→      if (!lastEntry || log[key].timestamp > lastEntry.timestamp) {
383→        lastEntry = log[key];
384→      }
385→    }
386→  }
387→
388→  if (!lastEntry) {
389→    return startingWeight; // First time - use starting weight
390→  }
391→
392→  const lastWeek = Math.floor((lastEntry.day - 1) / 7) + 1;
393→
394→  if (currentWeek > lastWeek) {
395→    // New week - suggest progression
396→    return Math.min(lastEntry.weight + increment, 80); // Cap at 80lbs
397→  }
398→
399→  return lastEntry.weight; // Same week - same weight
400→}
