402→// Increment weight for an exercise
403→function incrementWeight(exerciseKey, increment = 5) {
404→  const input = document.querySelector(`input[data-key="${exerciseKey}"]`);
405→  if (!input) return;
406→
407→  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 5;
408→  const newValue = Math.min(currentValue + increment, 80); // Cap at 80lbs
409→  input.value = newValue;
410→
411→  // Trigger save
412→  saveWeightInput(input);
413→}
414→
415→// Decrement weight for an exercise
416→function decrementWeight(exerciseKey, increment = 5) {
417→  const input = document.querySelector(`input[data-key="${exerciseKey}"]`);
418→  if (!input) return;
419→
420→  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 10;
421→  const newValue = Math.max(currentValue - increment, 5); // Min 5lbs
422→  input.value = newValue;
423→
424→  // Trigger save
425→  saveWeightInput(input);
426→}
