/* Basement Lab - Multi-Theme System */

/* =============================================
   BASE VARIABLES (shared across all themes)
   ============================================= */
:root {
  --radius: 8px;
  --transition: 0.2s;
  --danger: #ff4444;
  --warning: #ff9800;
}

/* =============================================
   THEME-SPECIFIC VARIABLES
   (accent colors, fonts, effects)
   ============================================= */

/* Cyberpunk (default) - Neon glow, high contrast, monospace */
[data-theme="cyberpunk"] {
  --accent: #00ff88;
  --accent-dim: #00cc6a;
  --font-family: 'Courier New', monospace;
  --glow: 0 0 20px rgba(0, 255, 136, 0.3);
  --shadow: none;
}

/* Material - Soft shadows, calm, system font */
[data-theme="material"] {
  --accent: #009688;
  --accent-dim: #00796b;
  --font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --glow: none;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

/* Ocean - Cool, clean, system font */
[data-theme="ocean"] {
  --accent: #2196f3;
  --accent-dim: #1976d2;
  --font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --glow: none;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
}

/* Ember - Warm, energetic, monospace */
[data-theme="ember"] {
  --accent: #ff7043;
  --accent-dim: #f4511e;
  --font-family: 'Courier New', monospace;
  --glow: 0 0 20px rgba(255, 112, 67, 0.3);
  --shadow: none;
}

/* =============================================
   MODE-SPECIFIC VARIABLES
   (backgrounds, text colors)
   ============================================= */

/* Dark mode */
[data-mode="dark"] {
  --bg-primary: #0a0a0a;
  --bg-secondary: #111111;
  --bg-card: #1a1a1a;
  --text-primary: #e0e0e0;
  --text-secondary: #aaaaaa;
  --border: #333333;
}

/* Light mode */
[data-mode="light"] {
  --bg-primary: #f5f5f5;
  --bg-secondary: #ffffff;
  --bg-card: #ffffff;
  --text-primary: #1a1a1a;
  --text-secondary: #666666;
  --border: #dddddd;
}

/* =============================================
   THEME + MODE COMBINATION OVERRIDES
   (accent adjustments for light backgrounds)
   ============================================= */

/* Cyberpunk light - darker green for readability */
[data-theme="cyberpunk"][data-mode="light"] {
  --accent: #00994d;
  --accent-dim: #007a3d;
  --glow: 0 0 20px rgba(0, 153, 77, 0.2);
}

/* Material light - slightly darker teal */
[data-theme="material"][data-mode="light"] {
  --accent: #00796b;
  --accent-dim: #00695c;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

/* Ocean light - slightly darker blue */
[data-theme="ocean"][data-mode="light"] {
  --accent: #1976d2;
  --accent-dim: #1565c0;
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
}

/* Ember light - slightly darker orange */
[data-theme="ember"][data-mode="light"] {
  --accent: #f4511e;
  --accent-dim: #e64a19;
  --glow: 0 0 20px rgba(244, 81, 30, 0.15);
}

/* =============================================
   GLOBAL RESET
   ============================================= */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: var(--font-family);
  background: var(--bg-primary);
  color: var(--text-primary);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  -webkit-font-smoothing: antialiased;
}

/* =============================================
   HEADER
   ============================================= */
header {
  background: var(--bg-secondary);
  padding: 1rem;
  text-align: center;
  border-bottom: 1px solid var(--accent);
  position: sticky;
  top: 0;
  z-index: 100;
  position: relative;
  box-shadow: var(--shadow);
}

.settings-btn {
  position: absolute;
  top: 50%;
  right: 1rem;
  transform: translateY(-50%);
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  width: 36px;
  height: 36px;
  border-radius: 50%;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.2rem;
  transition: all var(--transition);
}

.settings-btn:hover {
  border-color: var(--accent);
  color: var(--accent);
}

header h1 {
  font-size: 1.5rem;
  letter-spacing: 0.3em;
  color: var(--accent);
  text-shadow: var(--glow);
}

#day-counter {
  font-size: 1rem;
