  margin-top: 0.5rem;
}

#day-counter span {
  color: var(--accent);
  font-weight: bold;
}

/* =============================================
   SESSION PROGRESS BAR
   ============================================= */
#session-progress {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: transparent;
}

#session-progress-bar {
  height: 100%;
  width: 0%;
  background: var(--accent);
  box-shadow: var(--glow);
  transition: width 0.4s ease;
}

/* =============================================
   MAIN CONTENT
   ============================================= */
main {
  flex: 1;
  padding: 1rem;
  overflow-y: auto;
  padding-bottom: 100px;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1rem;
  margin-bottom: 1rem;
  box-shadow: var(--shadow);
}

#workout-header {
  border-bottom: 1px solid var(--border);
  padding-bottom: 1rem;
  margin-bottom: 1rem;
}

#workout-name {
  font-size: 1.3rem;
  color: var(--accent);
  margin-bottom: 0.25rem;
}

#workout-focus {
  font-size: 1rem;
  color: var(--text-secondary);
}

/* =============================================
   EXERCISE ITEMS
   ============================================= */
.exercise {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 1rem;
  margin-bottom: 0.75rem;
  box-shadow: var(--shadow);
}

.exercise-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 0.5rem;
}

.exercise-name {
  font-size: 1.1rem;
  font-weight: bold;
  color: var(--text-primary);
  flex: 1;
}

.video-btn {
  background: transparent;
  border: 1px solid var(--accent);
  color: var(--accent);
  padding: 0.25rem 0.5rem;
  font-size: 0.9rem;
  border-radius: 4px;
  cursor: pointer;
  font-family: inherit;
  transition: all var(--transition);
}

.video-btn:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.video-btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

.exercise-details {
  display: flex;
  gap: 1rem;
  font-size: 1rem;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
}

.exercise-details span {
  display: flex;
  align-items: center;
  gap: 0.25rem;
}

.exercise-note {
  font-size: 0.95rem;
  color: var(--accent-dim);
  font-style: italic;
  padding-top: 0.5rem;
  border-top: 1px dashed var(--border);
}

/* =============================================
   COMPLETED EXERCISE STATE
   ============================================= */
.exercise.completed {
  border-left: 3px solid var(--accent);
  opacity: 0.85;
}

.exercise.completed .exercise-name {
  color: var(--accent);
}

/* Done Button */
.done-btn {
  background: transparent;
  border: 1px solid var(--accent);
  color: var(--accent);
  padding: 0.4rem 0.75rem;
  font-size: 0.85rem;
  font-family: inherit;
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: bold;
}

.done-btn:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.done-btn.is-done {
  background: var(--accent);
  color: var(--bg-primary);
}

/* =============================================
   WEIGHT INPUT
   ============================================= */
.weight-input {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--border);
}

.weight-input label {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

.weight-input input {
  background: var(--bg-primary);
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 0.5rem;
  width: 80px;
  font-family: inherit;
  font-size: 1.1rem;
  border-radius: 4px;
  text-align: center;
}

.weight-input input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: var(--glow);
}

.weight-input .unit {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

/* Weight Controls (+/- buttons) */
.weight-controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.weight-btn {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  border: 1px solid var(--accent);
  background: transparent;
  color: var(--accent);
