  font-family: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--transition);
}

.weight-btn:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.weight-btn:active {
  transform: scale(0.95);
}

.suggested-hint {
  font-size: 0.9rem;
  color: var(--text-secondary);
  font-style: italic;
  margin-left: 0.5rem;
}

/* =============================================
   FEEDBACK SECTION
   ============================================= */
.feedback-section {
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--border);
}

.feedback-toggle {
  background: transparent;
  border: 1px solid var(--border);
